__kernel void hotspotOpt1(
    __global const float* pIn,
    __global const float* tIn,
    __global float* tOut,
    float stepDivCap,
    int numCols,
    int numRows,
    int layers,
    float ce,
    float cw,
    float cn,
    float cs,
    float ct,
    float cb,
    float cc)
{
    int x = get_global_id(0);
    int y = get_global_id(1);

    if (x >= numCols || y >= numRows)
        return;

    int nx = numCols;
    int ny = numRows;
    int nz = layers;
    float amb_temp = 80.0f;

    for (int z = 0; z < nz; z++)
    {
        int c = x + y * nx + z * nx * ny;

        int w = (x == 0) ? c : c - 1;
        int e = (x == nx - 1) ? c : c + 1;
        int n = (y == 0) ? c : c - nx;
        int s = (y == ny - 1) ? c : c + nx;
        int b = (z == 0) ? c : c - nx * ny;
        int t_idx = (z == nz - 1) ? c : c + nx * ny;

        tOut[c] = cc * tIn[c] + cw * tIn[w] + ce * tIn[e]
                + cs * tIn[s] + cn * tIn[n] + cb * tIn[b] + ct * tIn[t_idx]
                + stepDivCap * pIn[c] + ct * amb_temp;
    }
}
